func HelperStrToBinary5(exchange *ccxt.Exchange, str any) any {
	return exchange.Base64ToBinary(exchange.StringToBase64(str))
}
func TestBinaryToBase58() {
	exchange := ccxt.NewExchange().(*ccxt.Exchange)
	exchange.DerivedExchange = exchange
	exchange.InitParent(map[string]any{
		"id": "sampleexchange",
	}, map[string]any{}, exchange)
	assert(ccxt.IsEqual(exchange.ParseNumber(nil), nil), "GO skip trick")
	// @SKIP_START_GO
	// Test 1: Simple string
	var binary1 any = HelperStrToBinary5(exchange, "hello")
	Assert(ccxt.IsEqual(exchange.BinaryToBase58(binary1), "Cn8eVZg"))
	// Test 2: String with space
	var binary2 any = HelperStrToBinary5(exchange, "hello world")
	Assert(ccxt.IsEqual(exchange.BinaryToBase58(binary2), "StV1DL6CwTryKyV"))
	// Test 3: Short string
	var binary3 any = HelperStrToBinary5(exchange, "test")
	Assert(ccxt.IsEqual(exchange.BinaryToBase58(binary3), "3yZe7d"))
	// Test 4: Single byte
	var binary4 any = HelperStrToBinary5(exchange, "a")
	Assert(ccxt.IsEqual(exchange.BinaryToBase58(binary4), "2g"))
	// Test 5: Two bytes
	var binary5 any = HelperStrToBinary5(exchange, "ab")
	Assert(ccxt.IsEqual(exchange.BinaryToBase58(binary5), "8Qq"))
	// Test 6: Three bytes
	var binary6 any = HelperStrToBinary5(exchange, "abc")
	Assert(ccxt.IsEqual(exchange.BinaryToBase58(binary6), "ZiCa"))
	// Test 7: JSON-like binary
	var binary7 any = HelperStrToBinary5(exchange, "{\"key\":\"value\"}")
	Assert(ccxt.IsEqual(exchange.BinaryToBase58(binary7), "4SoiMiEYtTt5tPdi81Fik"))
}
